                disabled={!selectedAgent}
                className="px-4 py-2 text-sm bg-zinc-100 text-zinc-900 rounded font-semibold hover:bg-white disabled:opacity-40 disabled:cursor-not-allowed"
              >
                ▶ Run
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

